func (s *Server) Run() error {
	if err := s.initListener(); err != nil {
		return err
	}

	addr := net.JoinHostPort(s.bindAddr, strconv.Itoa(s.bindPort))
	hs := &http.Server{
		Addr:			addr,
		Handler:		s.handler,
		TLSConfig:		s.tlsConfig,
		ReadHeaderTimeout:	time.Minute,
	}

	s.hs = hs
	if s.tlsConfig == nil {
		go func() {
			_ = hs.Serve(s.l)
		}()
	} else {
		go func() {
			_ = hs.ServeTLS(s.l, "", "")
		}()
	}
	return nil
}
